#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=100005;
struct node
{
	int u,v,w,id;
	bool operator<(const node other) const
	{
		return w>other.w;
	}
} g[N];
struct Node
{
	int num,id,tim;
	bool operator<(const Node other) const
	{
		return num>other.num;
	}
};
vector<Node> qiao,che;
int n,m,q,fa[N],siz[N],block,id[N],vis[N],ans[N];
stack<int> st;
int find(int x)
{
	if(x==fa[x]) return x;
	return find(fa[x]);
}
void hebing(int x,int y)
{
	int fx=find(x),fy=find(y);
	if(fx==fy)
	{
		return ;
	}
	if(siz[fx]>siz[fy])
	{
		st.push(fy);
		siz[fx]+=siz[fy];
		fa[fy]=fx;
	}
	else
	{
		st.push(fx);
		siz[fy]+=siz[fx];
		fa[fx]=fy;
	}
}
void back(int lst)
{
	while(st.size()>lst)
	{
		int num=st.top();
		st.pop();
		siz[fa[num]]-=siz[num];
		fa[num]=num;
	}
}
void solve()
{
	sort(g+1,g+1+m);
	sort(che.begin(),che.end());
	for(int i=1;i<=m;i++)
	{
		id[g[i].id]=i;
	}
	vector<Node> qiao2;
	for(int i=0;i<qiao.size();i++)
	{
		Node tmp=qiao[i];
		vis[tmp.id]=-1;
		qiao2.push_back(Node{g[id[tmp.id]].w,tmp.id,0});
	}
	for(int i=0;i<qiao.size();i++)
	{
		Node tmp=qiao[i];
		qiao2.push_back(tmp);
	}
	for(int i=1;i<=n;i++)
	{
		fa[i]=i;
		siz[i]=1;
	}
	for(int i=0,it=1;i<che.size();i++)
	{
		while((it<=m)&&(g[it].w>=che[i].num))
		{
			if(!vis[g[it].id])
			{
				hebing(g[it].u,g[it++].v);
			}
		}
		int tmp=st.size();
		for(int i=0;i<qiao2.size();i++)
		{
			Node tmp2=qiao2[i];
			if(tmp2.tim<=che[i].tim)
			{
				vis[tmp2.id]=tmp2.num;
			}
		}
		for(int i=0;i<qiao2.size();i++)
		{
			Node tmp2=qiao2[i];
			if(vis[tmp2.id]>=che[i].num)
			{
				hebing(g[id[tmp2.id]].u,g[id[tmp2.id]].v);
			}
		}
		ans[che[i].tim]=siz[find(che[i].id)];
		back(tmp);
	}
	for(int i=0;i<qiao.size();i++)
	{
		Node tmp=qiao[i];
		g[id[tmp.id]].w=tmp.num;
		vis[tmp.id]=0;
	}
	che.clear();
	qiao.clear();
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n>>m;
	block=sqrt(m*log2(n));
	for(int i=1;i<=m;i++)
	{
		int u,v,w;
		cin>>u>>v>>w;
		g[i]=node{u,v,w,i};
	}
	cin>>q;
	for(int i=1;i<=q;i++)
	{
		int op;
		Node tmp;
		cin>>op>>tmp.id>>tmp.num;
		tmp.tim=i;
		if(op==1)
		{
			qiao.push_back(tmp);
		}
		else
		{
			che.push_back(tmp);
		}
		if((i%block)==0) solve();
	}
	if(q%block) solve();
	for(int i=1;i<=q;i++) cout<<'a'<<ans[i]<<"\n";
	return 0;
}
